impl Solution { pub fn subarrays_div_by_k(black_n: Vec<i32>, black_k: i32) -> i32 { let (mut black_ans, mut black_prefix, mut black_count) = (0, 0, vec![0; black_k as usize]); black_count[0] = 1; for x in black_n { black_prefix = (black_prefix + x % black_k + black_k) % black_k; black_ans += black_count[black_prefix as usize]; black_count[black_prefix as usize] += 1; } black_ans } }